REPO=$(gh repo view --json nameWithOwner -q .nameWithOwner) && cat > /tmp/claude-1000/-home-jwilger-projects-todo-list/4c972613-99c9-4b85-875a-303f16e8f47b/scratchpad/ruleset-signed.json <<'EOF'
{
  "name": "Require Signed Commits",
  "target": "branch",
  "enforcement": "active",
  "conditions": {
    "ref_name": {
      "include": ["refs/heads/*"],
      "exclude": []
    }
  },
  "rules": [
    {
      "type": "required_signatures"
    }
  ]
}
EOF
gh api -X POST "repos/$REPO/rulesets" --input /tmp/claude-1000/-home-jwilger-projects-todo-list/4c972613-99c9-4b85-875a-303f16e8f47b/scratchpad/ruleset-signed.json --jq '{id, name, enforcement}'

REPO=$(gh repo view --json nameWithOwner -q .nameWithOwner) && cat > /tmp/claude-1000/-home-jwilger-projects-todo-list/4c972613-99c9-4b85-875a-303f16e8f47b/scratchpad/ruleset-main.json <<'EOF'
{
  "name": "Main Branch Protection",
  "target": "branch",
  "enforcement": "active",
  "conditions": {
    "ref_name": {
      "include": ["refs/heads/main"],
      "exclude": []
    }
  },
  "rules": [
    {
      "type": "pull_request",
      "parameters": {
        "required_approving_review_count": 0,
        "dismiss_stale_reviews_on_push": true,
        "require_code_owner_review": false,
        "require_last_push_approval": false,
        "required_review_thread_resolution": true
      }
    },
    {
      "type": "required_status_checks",
      "parameters": {
        "required_status_checks": [
          {
            "context": "build"
          }
        ],
        "strict_required_status_checks_policy": true
      }
    },
    {
      "type": "non_fast_forward"
    },
    {
      "type": "deletion"
    },
    {
      "type": "required_linear_history"
    }
  ]
}
EOF
gh api -X POST "repos/$REPO/rulesets" --input /tmp/claude-1000/-home-jwilger-projects-todo-list/4c972613-99c9-4b85-875a-303f16e8f47b/scratchpad/ruleset-main.json --jq '{id, name, enforcement}'
